// AUTO-GENERATED by @aquila/stories compiler. Do not edit by hand.

import type { DialogueEntry } from '../../../../types';
import { CharacterId } from '../../../../characters';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "時間在這片濃霧籠罩的森林中變得毫無意義。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "窗外永遠是一片灰白色的霧氣,沒有日出,也沒有日落。天空永遠是那種介於黃昏與黎明之間的朦朧光線。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰和清水恵美無法分辨白天和黑夜,只能憑藉身體的疲憊感來判斷何時該睡覺,何時該起床。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他們在這棟小屋裡待了下來。美咲需要休養,而外面的濃霧和未知的危險讓他們暫時不敢輕舉妄動。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰仔細研讀了那本「森林傷患處理指南」,發現裡面提到可以在森林中採集某些藥草來加速傷口癒合。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "於是每「天」,他都會按照指南的指示,小心翼翼地到屋子附近的森林裡尋找藥草。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一種會發出淡藍色光芒的精靈苔蘚,生長在潮濕的岩石縫隙中。還有生長在古樹根部的銀葉草,葉片薄如蟬翼,泛著銀白色的光澤。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "清水恵美則負責照料美咲。她每天為美咲換藥、餵食、清理傷口,動作輕柔而細心,像是在照顧易碎的瓷器。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "美咲的狀況逐漸好轉。第一「週」,她只能虛弱地躺在床上,連說話都費力,只能用微弱的聲音說些感謝的話。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第二「週」,她能坐起來了,開始和恵美說些零碎的話。聊聊學校、朋友、家人,聲音雖然還很虛弱,但眼中有了生氣。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第三「週」,她嘗試下床走動。雖然腿還有些疼,每走一步都要咬緊牙關,但已經能勉強行走。" },
    { characterId: CharacterId.TakahashiMisaki, character: "高橋美咲", dialogue: "(扶著牆壁,一瘸一拐地走了幾步,臉上露出驚喜)我...我好像可以走了...真的可以走了!" },
    { characterId: CharacterId.TakahashiMisaki, character: "高橋美咲", dialogue: "雖然還是有點痛,但比起之前...已經好太多了!謝謝你們...真的謝謝你們..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(溫和地)別勉強。妳的傷口雖然癒合了,但肌肉還需要時間恢復。再休息幾天,等完全能走了再說。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "就這樣,三個人在這座與世隔絕的小屋裡,度過了不知是幾週還是幾個月的時光。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "霧氣從未散去,外面的世界彷彿靜止了。時間失去了意義,只剩下單調的日常——採藥、煮飯、換藥、休息。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "而在這片靜止中,美咲的傷口一天天癒合,她的笑容也慢慢回到了臉上。原本蒼白的臉色漸漸紅潤,眼神也恢復了活力。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "又過了幾「天」,美咲終於能夠正常行走了。她在屋內來回踱步,測試著自己的腿。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "雖然偶爾還會感到腿部有些僵硬,走久了會有點酸,但已經不影響正常行動。" },
    { characterId: CharacterId.TakahashiMisaki, character: "高橋美咲", dialogue: "(活動著手臂和腿,做著伸展動作,臉上露出如釋重負的笑容)終於好了...真的完全好了!" },
    { characterId: CharacterId.TakahashiMisaki, character: "高橋美咲", dialogue: "謝謝你們照顧我這麼久...如果沒有你們,我可能早就...早就死在那片森林裡了..." },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(微笑著,溫柔地)別這麼說...我們是同伴嘛...互相幫助是應該的...太好了...美咲能恢復真是太好了..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "那就好。妳要多謝恵美,她這段時間一直在照顧妳,幫妳換藥餵飯,比我細心多了。" },
    { characterId: CharacterId.TakahashiMisaki, character: "高橋美咲", dialogue: "(感激地握住清水恵美的手)恵美...真的謝謝妳...妳就像我姐姐一樣..." },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(臉紅,小聲地)沒...沒什麼啦..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "短暫的溫馨氣氛後,清水恵美的表情突然變得嚴肅起來。她深吸一口氣,像是下定了決心。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(突然認真起來,語氣帶著一絲急切)那個...李杰先生...美咲...我們是不是該出發了?" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(有些意外,放下手中的碗)出發?現在?妳是說離開這裡?" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(點頭,聲音比平時更堅定)對...我們已經在這裡待太久了...山本大叔他們...還有其他走散的學生..." },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "我們應該繼續找他們...他們可能也受傷了,可能需要幫助...我們不能一直躲在這裡..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰注意到清水恵美的表情有些不同尋常。平時總是怯生生、需要依賴他的她,此刻眼神中卻帶著一種罕見的堅定。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "甚至可以說是...急迫。那種急迫感就像是有什麼東西在催促著她,讓她無法繼續待在這個安全的地方。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(內心)恵美今天...有點不太一樣。她平常不是這麼主動的人,總是跟在我後面,等我做決定。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(內心)現在卻主動提出要離開...是因為擔心山本大叔他們的安危嗎?還是...有什麼其他原因?" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(看著清水恵美,緩緩點頭)妳說得對。我們確實該動身了。在這裡待得越久,山本大叔他們的處境可能就越危險。" },
    { characterId: CharacterId.TakahashiMisaki, character: "高橋美咲", dialogue: "(也點頭,語氣認真)我也想找到其他人...拓海、健太、明日香...他們也在森林裡..." },
    { characterId: CharacterId.TakahashiMisaki, character: "高橋美咲", dialogue: "而且當時我們跑散了,我不知道他們現在怎麼樣了...拓海當時手臂也被砍傷了...不知道他撐不撐得住..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(想起什麼,從口袋裡掏出那張皺褶的地圖)說起來,我們還有那張從車站拿到的地圖..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰將地圖攤開在桌上。恵美和美咲湊過來看。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(看了一眼,搖搖頭)這張地圖...我們之前就發現了...上面只有道路,沒有建築物標記,也沒辦法定位我們的位置..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(嘆氣)對...這張地圖基本上沒什麼用。我們連自己在哪裡都不知道。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰正準備收起地圖時,清水恵美突然想起了什麼。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(眼睛一亮)對了!李杰先生!我記得我之前在書櫃上看到過另一張地圖!" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(驚訝地)什麼?另一張地圖?在哪裡?" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(指向房間角落的舊書櫃)就在那邊!我之前整理房間的時候看到的,但當時沒有仔細看..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰快步走向書櫃,在最上層找到了一張折疊整齊的羊皮紙。紙張看起來很舊,但保存得很好。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他小心翼翼地將它取下來,攤開在桌上。三人立刻圍了過來。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(驚喜地)這張地圖...比車站那張詳細多了!" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這張新地圖繪製精細,標註清晰。上面不僅標示了道路,還清楚地標出了森林中的各個建築物。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "最重要的是,地圖中央有一棟小屋的標記,旁邊用工整的筆跡寫著「避難小屋」。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(指著地圖中央的標記,興奮地)這裡!這就是我們現在的位置!" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(仔細研究地圖)沒錯...從這棟避難小屋看,有幾個不同的方向..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰的手指在地圖上移動,仔細分析著每一條路線。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "往西邊,有一條小路。看起來這條小路會匯入一條主要道路,主要道路通往森林中心..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "往北邊,道路通往一個交叉路口...這個路口..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰拿起從車站得到的那張舊地圖對照。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "這個路口就是車站地圖上標示的那個!從那個路口可以回到車站,或者走主幹道進入森林,又或者前往下一個車站..." },
    { characterId: CharacterId.TakahashiMisaki, character: "高橋美咲", dialogue: "(湊近看)那南邊呢?" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(皺眉)南邊...地圖到這裡就結束了,沒有標示南邊通往哪裡。可能是未探索的區域,也可能是繪製地圖的人沒去過那裡。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(看著地圖,思考著)西邊、北邊、南邊...我們該往哪個方向走呢?" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "房間陷入了短暫的沉默。三人都盯著地圖,思考著該如何選擇。" },
    { characterId: CharacterId.TakahashiMisaki, character: "高橋美咲", dialogue: "(不確定地)北邊的話...可以回車站求救...或者去下一個車站看看有沒有人..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(搖頭)回車站不太現實。那個車站荒廢已久,而且我們來的時候就發現那裡空無一人。至於下一個車站..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "我們根本不知道距離有多遠,也不知道路上會遇到什麼。帶著美咲剛剛康復的身體,走長途風險太大。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(猶豫了一下,然後伸手指向地圖的西邊,聲音帶著一絲堅定)我覺得...我們應該往西邊走。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(看向她)西邊?為什麼?" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(垂下眼簾,輕聲說)我...我也說不上來...就是有種感覺..." },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "西邊的小路會通往森林中心的主要道路...山本大叔他們...還有其他人...我覺得他們應該在那個方向..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰仔細觀察著清水恵美的表情。她低著頭,雙手緊緊握在一起,看起來依然是那個膽怯的女孩。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但她的語氣中卻有一種無法忽視的確信,那種篤定的感覺,就像是她真的知道什麼一樣。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(內心)又是這種「感覺」...她好像對西邊那個方向特別堅持..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(內心)是直覺嗎?還是她真的知道些什麼?為什麼她會這麼確定?" },
    { characterId: CharacterId.TakahashiMisaki, character: "高橋美咲", dialogue: "(看看兩人)我...我覺得恵美說得有道理...主要道路上應該比較容易找到人..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(沉思片刻,最後點頭)好吧。既然妳有這種強烈的感覺,那就往西邊走。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "不過妳要記住,如果走了幾個小時還是沒有發現任何線索,我們就要考慮改變方向。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(抬起頭,眼中閃過一絲難以察覺的...什麼情緒,但轉瞬即逝)謝謝...李杰先生...我相信這個方向是對的..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "那我們什麼時候出發?" },
    { characterId: CharacterId.TakahashiMisaki, character: "高橋美咲", dialogue: "現在嗎?" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "先收拾一下。我們帶上乾糧、水和藥草。這次不知道要走多久才能找到下個避難所。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三人開始收拾行李。李杰將剩餘的乾糧、水壺和藥草裝進在屋內找到的一個舊背包裡。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "清水恵美找到了幾條乾淨的布條,可以用來包紮傷口。美咲則將那本「森林傷患處理指南」小心地收好。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰將新找到的詳細地圖也小心地折好,放進口袋。這張地圖比車站那張有用多了。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "收拾完畢後,李杰背上背包,沉甸甸的重量壓在肩上。他環顧小屋,最後看了一眼這個庇護了他們許久的地方。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(對著空蕩蕩的小屋)謝謝你...不管你是誰建造的,是誰維護的...謝謝你救了我們。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(也輕聲說)謝謝..." },
    { characterId: CharacterId.TakahashiMisaki, character: "高橋美咲", dialogue: "謝謝..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "走吧。往西邊。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三人推開門,再次踏入那片永恆的濃霧之中。冰冷的空氣立刻撲面而來,讓人打了個寒顫。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "霧氣依然濃厚,能見度依然極低。李杰拿出手機照明,走在前面開路。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "清水恵美緊跟在他身後,不時指引著方向。而美咲則跟在最後,雖然腿還有些不適,但勉強能跟上步伐。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他們沿著地圖上標示的西邊小路,一步步朝著森林中心的主要道路前進。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰心中依然有些疑惑——為什麼恵美會這麼堅持往西邊走?那種強烈的「感覺」到底是什麼?" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但他沒有多想,只是將這份疑惑暫時壓在心底,專注於前方未知的旅程。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(內心)希望我們的選擇是對的...山本大叔,還有那些走散的學生...等著我們。森林中心裡...到底有什麼?" },
];
